  hoverAnchor,
  unhoverAnchor,
  waitForTooltip,
  waitForTooltipToClose,
} from './test-utils'
import { installMockMutationObserver } from './mutation-observer-test-utils'

jest.mock('@floating-ui/dom', () => {
  const originalModule = jest.requireActual('@floating-ui/dom')
  return {
    ...originalModule,
